(function(){'use strict';var style = document.createElement('style');style.textContent = [
'.sa{','opacity:0;transform:translateY(28px);','transition:opacity .6s ease,transform .6s ease;','will-change:opacity,transform;','}','.sa.sa-visible{opacity:1;transform:translateY(0);}','.sa-left{transform:translateX(-44px)translateY(0);}','.sa-left.sa-visible{transform:translateX(0);}','.sa-right{transform:translateX(44px)translateY(0);}','.sa-right.sa-visible{transform:translateX(0);}','.sa-scale{transform:scale(.88)translateY(0);opacity:0;}','.sa-scale.sa-visible{transform:scale(1);opacity:1;transition:opacity .5s ease,transform .5s cubic-bezier(.34,1.36,.64,1);}','.sa-zoom{transform:scale(.94);opacity:0;}','.sa-zoom.sa-visible{transform:scale(1);opacity:1;}','.sa-d1{transition-delay:.07s;}','.sa-d2{transition-delay:.14s;}','.sa-d3{transition-delay:.21s;}','.sa-d4{transition-delay:.28s;}','.sa-d5{transition-delay:.35s;}','.sa-d6{transition-delay:.42s;}','@media(prefers-reduced-motion:reduce){','.sa,.sa-left,.sa-right,.sa-scale,.sa-zoom{','opacity:1!important;transform:none!important;transition:none!important;','}','}'
].join('');document.head.appendChild(style);var RULES = [{sel:'.section-title',anim:'up',cascade:false},{sel:'.section-label',anim:'up',cascade:false},{sel:'.page-hero h1',anim:'up',cascade:false},{sel:'.article-hero h1',anim:'up',cascade:false},{sel:'.cat-section-title',anim:'up',cascade:false},{sel:'.why-card',anim:'left',cascade:true},{sel:'.info-card',anim:'left',cascade:true},{sel:'.stat-card',anim:'scale',cascade:true},{sel:'.stat-num',anim:'scale',cascade:true},{sel:'.product-card',anim:'zoom',cascade:true},{sel:'.project-card',anim:'zigzag',cascade:true},{sel:'.brand-chip',anim:'scale',cascade:true},{sel:'.brand-section',anim:'up',cascade:false},{sel:'.article-featured',anim:'up',cascade:false},{sel:'.article-card',anim:'zoom',cascade:true},{sel:'.faq-item',anim:'up',cascade:true},{sel:'.type-card',anim:'scale',cascade:true},{sel:'.step-card',anim:'up',cascade:true},{sel:'.testimonial-card',anim:'scale',cascade:true},{sel:'.sidebar-card',anim:'up',cascade:true},{sel:'.cta-section',anim:'up',cascade:false},{sel:'.cta-banner',anim:'up',cascade:false},{sel:'.hero-card',anim:'right',cascade:true},{sel:'.cat-card',anim:'zoom',cascade:true},{sel:'.client-chip',anim:'scale',cascade:true},{sel:'.mission-card',anim:'left',cascade:true},];var seen = new WeakSet();function animClass(anim,idx){if(anim === 'left')return 'sa sa-left';if(anim === 'right')return 'sa sa-right';if(anim === 'scale')return 'sa sa-scale';if(anim === 'zoom')return 'sa sa-zoom';if(anim === 'zigzag')return idx % 2 === 0 ? 'sa sa-left' : 'sa sa-right';return 'sa';}function isAboveFold(el){return el.getBoundingClientRect().top < window.innerHeight - 80;}function applyRule(rule){var els = document.querySelectorAll(rule.sel);var parentMap ={};els.forEach(function(el){var pid = el.parentElement ?(el.parentElement._saId ||(el.parentElement._saId = ++applyRule._id)): 0;if(!parentMap[pid])parentMap[pid] = [];parentMap[pid].push(el);});Object.values(parentMap).forEach(function(group){var groupIdx = 0;group.forEach(function(el){if(seen.has(el)|| isAboveFold(el))return;seen.add(el);var classes = animClass(rule.anim,groupIdx).split(' ');classes.forEach(function(c){if(c)el.classList.add(c);});if(rule.cascade && groupIdx > 0 && groupIdx <= 6){el.classList.add('sa-d' + Math.min(groupIdx,6));}groupIdx++;});});}applyRule._id = 0;function observe(){if(!('IntersectionObserver' in window)){document.querySelectorAll('.sa').forEach(function(el){el.classList.add('sa-visible');});return;}var io = new IntersectionObserver(function(entries){entries.forEach(function(entry){if(entry.isIntersecting){entry.target.classList.add('sa-visible');io.unobserve(entry.target);}});},{threshold: 0.10,rootMargin: '0px 0px -36px 0px'});document.querySelectorAll('.sa').forEach(function(el){io.observe(el);});}function init(){RULES.forEach(applyRule);observe();}if(document.readyState === 'loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}})();